using UnityEngine;
using UnityEngine.UIElements;
using System.Text;
public class Script
{
    public static object Main()
    {
        var sb = new StringBuilder();
        var docs = Object.FindObjectsOfType<UIDocument>();
        sb.AppendLine("UIDocuments: " + docs.Length);
        foreach (var doc in docs)
        {
            if (doc.rootVisualElement == null) { sb.AppendLine("  null root"); continue; }
            var btns = doc.rootVisualElement.Query<Button>().ToList();
            sb.AppendLine("  doc=" + doc.gameObject.name + " buttons=" + btns.Count);
            foreach (var btn in btns)
                sb.AppendLine("    btn: name=" + btn.name + " visible=" + btn.resolvedStyle.display);
        }
        return sb.ToString();
    }
}
